1	export interface Item {
2	  type: string;
3	}
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 1.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	function roundUpToWholeG(amount: number): number {
16	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
17	  return Math.ceil(Math.round(amount * 100) / 100);
18	}
19	
20	function premiumFor(item: Item): number {
21	  const basePremium = BASE_PREMIUMS[item.type];
22	  return roundUpToWholeG(basePremium * FIRST_INSURANCE_SURCHARGE);
23	}
24	
25	export function quote(
26	  _customer: { yearsWithMHPCO: number },
27	  items: Item[],
28	  _previousContracts?: number,
29	): number {
30	  const itemsTotal = items.reduce((sum, item) => sum + premiumFor(item), 0);
31	  return itemsTotal + PROCESSING_FEE;
32	}
33	
34	export function claim(): number {
35	  return undefined as unknown as number;
36	}
